def _resolve_font_path(bold=False):
    """한글 폰트 경로를 OS에 맞게 자동으로 찾는 함수. env var로 override 가능."""
    env_key = 'STATS_FONT_BOLD_PATH' if bold else 'STATS_FONT_PATH'
    if os.environ.get(env_key):
        return os.environ[env_key]
    system = platform.system()
    if system == 'Linux':
        suffix = 'NotoSerifCJK-Bold.ttc' if bold else 'NotoSansCJK-Regular.ttc'
        return f'/usr/share/fonts/opentype/noto/{suffix}'
    elif system == 'Darwin':  # macOS
        candidates = [
            '/System/Library/Fonts/AppleSDGothicNeo.ttc',  # 최고품질 한글 폰트
            '/Library/Fonts/NanumGothic.ttf',
            '/System/Library/Fonts/Supplemental/AppleGothic.ttf',
        ]
        for p in candidates:
            if os.path.exists(p):
                return p
    raise FileNotFoundError(f'Korean font not found. Set {env_key} in .env to override.')

plt.rcParams['axes.unicode_minus'] = False  # 마이너스 기호 깨짐 방지
font_path = _resolve_font_path(bold=False)

