    df['지역 대분류'] = df['지역 대분류'].astype(category_order)
    df.sort_values('지역 대분류', inplace=True)  # 정렬해주면 그래프 그릴때 위에서 지정해 준 순서 대로 x축에 나타남

    new_order = ['공고 제목', '등록일', '플랫폼', '링크',
                 '약국 명칭', '지역 대분류', '지역', '경력 요구', '월차',
                 '공고에 급여 명시 여부', '내가 검토시 체크', 'LLM model',
                 '일회성 근무 여부', '일회성 근무 시급',
                 '시급(엄밀히)', '세후 월급', '시간/week', '주당 근무 일수',
                 '평일 출근 시각', '평일 퇴근 시각', '평일 근무 일수',
                 '주말 퇴근 시각', '주말 출근 시각', '주말 근무 일수',
                 '본문', 'GPT 요약문', 'GPT 2nd Run', '내 코멘트']

    df = df[new_order]

    df.info()

    """# 워터마크 넣는 함수"""

    # @title Bold체 font 경로
    watermark_font_path = _resolve_font_path(bold=True)

    def add_watermark(image_file_name, watermark_text='CJM',
                      rotation_angle=20, font_size_parameter=7):
        image_path = os.path.join(output_dir, '{}.png'.format(image_file_name))
        output_path = os.path.join(output_dir, '{}_워터마크.png'.format(image_file_name))

        image = Image.open(image_path).convert("RGBA")

        # 워터마크 텍스트의 폰트 및 크기 설정
        font_size = int(image.height * font_size_parameter/100) # 이미지 세로 길이의 15% 수준으로 폰트 크기를 설정.
        font = ImageFont.truetype(watermark_font_path, font_size)  # 굵은 폰트 사용

        draw = ImageDraw.Draw(image)
        # textbbox를 사용하여 텍스트의 경계 박스 얻기
        left, top, right, bottom = draw.textbbox((0, 0), text=watermark_text, font=font)

        # 텍스트의 너비와 높이 계산
        text_width = right - left
        text_height = bottom - top

        # 워터마크를 그릴 투명한 이미지 생성
        padding = 200 # 워터마크의 일부분이 잘리는 문제를 해결하기 위한 여백 추가
        text_image = Image.new('RGBA', (text_width, text_height + padding), (0, 0, 0, 0))
        draw = ImageDraw.Draw(text_image)

        # 그림자 그리기
        shadow_color = (0, 0, 0, 128)  # 반투명 검정색 : 제일 마지막에 128이 불투명도를 설정하는 숫자임.
        draw.text((2, 2), watermark_text, font=font, fill=shadow_color)

        # 텍스트 그리기
        text_color = (255, 255, 255, 204)  # 반투명 흰색 : 204면 불투명도 80% 수준임. (d.t. 204/255 = 0.8)
        draw.text((0, 0), watermark_text, font=font, fill=text_color)

        # 텍스트 이미지 회전
        rotated_text_image = text_image.rotate(rotation_angle, expand=True)

        # 회전된 텍스트 이미지를 원본 이미지의 중앙에 배치
        x = (image.width - rotated_text_image.width) // 2
        y = (image.height - rotated_text_image.height) // 2

        # 투명한 이미지에 회전된 텍스트 이미지를 붙이기
        tmp_img = Image.new('RGBA', image.size, (0,0,0,0))
        tmp_img.paste(rotated_text_image, (int(x), int(y)), rotated_text_image)

        # 이미지 합치기
        watermarked = Image.alpha_composite(image, tmp_img)

        # 이미지 저장
        watermarked.save(output_path, "PNG")
        os.remove(image_path)  # raw 파일 삭제, 워터마크 버전만 유지

    # 함수 사용 예
    # title = '등록일별 공고 수'
    # add_watermark(image_file_name=title,  # 파일 이름
    #               watermark_text='YST',   # 워터마크 문구
    #               rotation_angle=20,      # 워터마크 회전 각도
    #               font_size_parmeter=7)  # 워터마크 크기가 이미지 세로 길이의 몇%가 되게 할건지

    """# Matplotlib 스타일 프리셋 설정하기

    Matplotlib에는 다양한 미리 정의된 스타일이 있어, 그 중에서 선택하여 그래프의 전반적인 외형을 쉽게 바꿀 수 있습니다. 여기 몇 가지 인기 있는 스타일을 소개합니다:

    0. **default** - Matplotlib이 처음 설치됐을 때의 기본 설정
    1. **classic** - Matplotlib의 전통적인 스타일을 유지합니다. 업데이트 이전의 Matplotlib 그래프 스타일을 선호하는 사용자에게 적합합니다.
    2. **seaborn** - Seaborn 라이브러리의 기본 스타일을 모방한 것으로, 현대적이고 깔끔한 외형을 제공합니다.
    3. **seaborn-darkgrid** - 배경에 어두운 그리드를 사용하여 Seaborn 스타일을 적용한 것입니다.
    4. **seaborn-whitegrid** - 배경에 밝은 그리드를 사용하여 데이터 포인트를 강조합니다.
    5. **grayscale** - 모든 그래프 요소를 회색조로 표시하여 프린트하기 좋은 그래프를 제공합니다.
    6. **bmh** - Bayesian Methods for Hackers 책에서 사용된 스타일을 모방한 것으로, 일종의 모던하고 심플한 디자인을 제공합니다.
    7. **dark_background** - 어두운 배경에 밝은 색의 텍스트와 선을 사용하여, 프레젠테이션에 적합한 독특한 외형을 제공합니다.
    8. **fivethirtyeight** - 538 블로그에서 사용된 스타일을 모방한 것으로, 통계적 그래프에 적합하며 대중적인 외형을 제공합니다.
    9. **Solarize_Light2** - Solarized 색상 팔레트의 밝은 버전을 사용하여, 눈에 편안한 색상 조합을 제공합니다.
    10. **ggplot** - R 언어에서 사용되는 유명한 시각화 패키지 ggplot2의 외관을 모방한 스타일

    스타일을 적용하는 방법은 매우 간단합니다. 사용하고 싶은 스타일의 이름을 `plt.style.use()` 함수에 전달하면 해당 스타일이 그래프에 적용됩니다. 예를 들어, Seaborn 스타일을 적용하고 싶다면 다음과 같이 코드를 작성하면 됩니다:

    ```python
    import matplotlib.pyplot as plt

    plt.style.use('seaborn')
    ```
    """

    plt.style.use('bmh')

    # style 바꾸고 난 다음에 폰트 한 번 더 불러와줘야 함.

