    # @title 함수 정의) 풀타임 근무 시급 scatter plot  (나의 data point 추가 버전 : 별표로 찍힘)
    def plot_full_time_scatter_with_my_data(df, my_X, my_Y, fig_title, big_category=None):
        """
        주어진 데이터 프레임에서 풀타임 근무에 해당하는 데이터를 추출하고 시급과 주당 근무 시간을 비교하는 그래프를 그립니다.
        나의 근무 시간과 시급을 강조하기 위한 별도 포인트도 추가됩니다.

        Args:
            df (DataFrame): 근무 데이터 프레임
            my_X (float): 나의 주당 근무 시간
            my_Y (float): 나의 시급
            fig_title (str): 그래프 제목
        """

        # 장기 근무만 필터링
        df_long = df[df['일회성 근무 여부'] == 'No']

        # 풀타임 근무만 필터링 (주당 근무 시간이 36시간 이상인 경우)
        df_long = df_long[df_long['시간/week'] >= 36]

        # 지역 필터링
        if big_category:
            df_long = df_long[df_long['지역 대분류'] == big_category]
        else:
            pass

        # 그래프의 크기 설정
        plt.figure(figsize=(12, 8))

        # 산점도 그리기
        sns.scatterplot(data=df_long, x='시간/week', y='시급(엄밀히)', s=40, color='black', alpha=0.3)

        # 회귀선 추가
        sns.regplot(data=df_long, x='시간/week', y='시급(엄밀히)', scatter=False, line_kws={'color': 'red'})

        # 나의 근무 시간과 시급에 대한 포인트 추가 (초록색 별표)
        if my_X and my_Y:
            plt.scatter(my_X, my_Y, color='blue', marker='*', s=300, label='My point')

        # 그래프 제목 설정
        plt.title(fig_title + '\n', fontsize=18, fontweight='bold')

        # x축 라벨 설정
        plt.xlabel('\n주당 근무 시간 (단위 : 시간)')

        # y축 라벨 설정
        plt.ylabel('시급 (단위 : 만 원)\n')

        # y축 범위 설정
        plt.ylim(1.7, 4.2)

        # x축 틱 간격 설정
        plt.xticks(np.arange(33, df_long['시간/week'].max() + 3, 1))

        # 그리드 추가
        plt.grid(True)

        # 레이아웃 조정
        plt.tight_layout()

