    # 그래프 제목 및 라벨
    plt.title(fig_title + '\n', fontsize=18, fontweight='bold')
    plt.xlabel('\n지역 대분류', fontsize=15)
    plt.ylabel('시급 (단위 : 만 원)\n', fontsize=15)
    plt.grid(True)

    # legend 추가
    # 구인 공고와 IQR 범례에 사용할 맞춤 마커 생성
    job_marker = mlines.Line2D([], [], color='black', marker='o', linestyle='None', markersize=5, alpha=0.4, label='구인 공고')
    iqr_box = mlines.Line2D([], [], marker='s', color='black', markerfacecolor='yellow', markeredgewidth=1,
                        markeredgecolor='black', linestyle='None', markersize=15, alpha=0.3, label='IQR (interquartile range)')

    plt.legend(handles=[job_marker, iqr_box], loc='upper right', fontsize=11)

    # y축 여백 설정
    plt.ylim(df_comparison['시급(엄밀히)'].min() - stds.max(), df_comparison['시급(엄밀히)'].max() + stds.max())

    # 레이아웃 조정
    plt.tight_layout()

    # 그래프 저장
    plt.savefig(os.path.join(output_dir, '{}.png'.format(fig_title)), format='png', dpi=300) # 일반적으로 인쇄용으로는 최소 300 DPI가 권장됨. 화면 보기용으로는 150 DPI도 충분

    # 이미지에 워터마크 넣기
    add_watermark(image_file_name=fig_title, rotation_angle=15, font_size_parameter=7)

    # ===================================== Statistics ===========================================
    # ANOVA 분석
    anova_result = f_oneway(*data) # *는 언패킹 연산자임. f_oneway(data[0], ... , data[N])과 같은 역할.

    # ANOVA 결과를 출력
    anova_text = f"ANOVA 결과: F-statistic = {anova_result.statistic:.2f}, p-value = {anova_result.pvalue:.10f}"
    print(anova_text)

    # 사후검정(post-hoc test) : Tukey's HSD
    tukey_result = pairwise_tukeyhsd(endog=df_comparison['시급(엄밀히)'], groups=df_comparison['지역 대분류'], alpha=0.05)
    print(tukey_result)
    # ===========================================================================================

    # 그래프 표시

    print()
    tukey_result.summary()

    # @title 풀타임 / 파트타임 두 집단으로 구분해서 scatter + box plot 그리고 t-test 하기

    fig_title = '풀타임 vs 파트타임 시급 비교'

    # 데이터프레임 복사
    df_comparison = df.copy()

    # 지속성 근무만 선택
    df_comparison = df_comparison[df_comparison['일회성 근무 여부'] == 'No']

    # 새로운 변수 설정
    variable_of_interest = '시간/week'

    # 세 집단 나누기
    df_comparison['집단'] = pd.cut(df_comparison[variable_of_interest], bins=[-np.inf, 22, 35.99, np.inf], labels=['파트타임', '애매한 타임', '풀타임'])  # 파트타임 <= 22 < 애매한 타임 <=  35 < 풀타임 이렇게 부등식 구간이 나뉘는 것 같음.

    # 그래프 크기 및 초기 설정
    plt.figure(figsize=(6,10))

    # 카테고리별 평균 및 표준 편차, n수 계산
    grouped = df_comparison.groupby('집단', observed=False)['시급(엄밀히)']
    means = grouped.mean()
    stds = grouped.std()
    num_data = grouped.count()

    # Dot plot
    sns.stripplot(x='집단', y='시급(엄밀히)', data=df_comparison, jitter=0.03, alpha=0.3, color='black')  # jitter 기능 쓰기 위해 seaborn 씀

    # Box plot
    positions = range(len(grouped))  # 각 그룹별 위치 설정

    # 각 그룹의 데이터를 리스트로 준비
    data = [group for name, group in grouped]

    plt.boxplot(data, positions=positions, patch_artist=True, showfliers=False, widths=0.2, # 박스의 너비
                boxprops=dict(facecolor='yellow', color='black', alpha=0.2),
                whiskerprops=dict(color='green', alpha=0),
                capprops=dict(color='black', alpha=0),
                flierprops=dict(marker='o', color='yellow', alpha=0, markersize=5),
                medianprops=dict(color='gray', alpha=0)
    )

    # 카테고리 위치 조정
    plt.xticks(positions, grouped.groups.keys(), rotation=0)

    means_by_work_hours = {}

    for i, region in enumerate(list(means.index)):
        means_by_work_hours.setdefault(region, means[region])

        # 평균값을 점으로 표시
        plt.plot(i, means[region], 'rs', markersize=7, zorder=3)  # 'ro'는 빨간색 원형 마커, zorder 값이 클수록 화면의 더 위에 쌓임

        # 평균 시급 값 숫자로 표시, 텍스트 위치 오른쪽으로 조정
        plt.text(i + 0.07 , means[region], f'   {means[region]:.2f}', fontsize=15, ha = 'left', color='red', zorder=4)

        # 카테고리별 공고 개수 표시
        position = df_comparison['시급(엄밀히)'].min() - stds.max()*0.7
        plt.text(i, position, f'n = {num_data[region]}', fontsize=12, ha = 'center', color='black')

    # 그래프 제목 및 라벨
    plt.title(fig_title + '\n', fontsize=18, fontweight='bold')
    plt.xlabel('\n주당 근무 시간 (단위 : 시간)', fontsize=15)
    plt.ylabel('시급 (단위 : 만 원)\n', fontsize=15)
    #plt.xticks([0,1],['22 이하', '36 이상']) # 내가 N수 보고 임의로 지정해주는거라 서로 바뀌지 않았는지 잘 확인해야 함.
    plt.grid(True)

    # legend 추가
    # 구인 공고와 IQR 범례에 사용할 맞춤 마커 생성
    job_marker = mlines.Line2D([], [], color='black', marker='o', linestyle='None', markersize=5, alpha=0.4, label='구인 공고')
    iqr_box = mlines.Line2D([], [], marker='s', color='black', markerfacecolor='yellow', markeredgewidth=1,
                        markeredgecolor='black', linestyle='None', markersize=15, alpha=0.3, label='IQR (interquartile range)')

    plt.legend(handles=[job_marker, iqr_box], loc='upper right', fontsize=11)

    # y축 여백 설정
    plt.ylim(df_comparison['시급(엄밀히)'].min() - stds.max(), df_comparison['시급(엄밀히)'].max() + stds.max())

    # 레이아웃 조정
    plt.tight_layout()

    # 그래프 저장
    plt.savefig(os.path.join(output_dir, '{}.png'.format(fig_title)), format='png', dpi=300) # 일반적으로 인쇄용으로는 최소 300 DPI가 권장됨. 화면 보기용으로는 150 DPI도 충분

    # 이미지에 워터마크 넣기
    add_watermark(image_file_name=fig_title, rotation_angle=15, font_size_parameter=7)

    # ===================================== Statistics ===========================================
    # 양쪽 극단의 두 집단에 대해 독립표본 t-검정 수행 ( 22이하 vs 36이상 )
    t_stat, p_value = stats.ttest_ind(data[0], data[2], equal_var=False)  # equal_var=False는 두 그룹의 분산이 같지 않을 때 사용
    print(f't-statistic: {t_stat:.3f}')
    print(f'p-value: {p_value:.15f}')
    alpha = 0.05  # 유의수준 설정
    if p_value < alpha:  # 결과 해석
        print("두 그룹 간의 평균 시급 차이는 통계적으로 유의미합니다.\n")
    else:
        print("두 그룹 간의 평균 시급 차이는 통계적으로 유의미하지 않습니다.\n")

    # 자유도 계산
    dfn = len(data[0]) + len(data[2]) - 2

    # 효과 크기 계산 (Cohen's d)
    mean_diff = data[0].mean() - data[2].mean()
    pooled_std = np.sqrt((data[0].var() + data[2].var()) / 2)
    cohen_d = mean_diff / pooled_std

    # 결과 출력
    print(f"독립표본 t-검정 결과: t({dfn}) = {t_stat:.3f}, p = {p_value:.3e}, Cohen's d = {cohen_d:.3f}")
    print(f"파트타임 평균 시급: {data[0].mean():.3f} (SD = {data[0].std():.3f})")
    print(f"풀타임 평균 시급: {data[2].mean():.3f} (SD = {data[2].std():.3f})")
    print('\n')
    # ===========================================================================================

    # 그래프 표시

    # 풀타임 / 파트타임 공고수 카운트
    full_time_N = int(num_data['풀타임'])  # numpy.int64가 아닌 그냥 int로 바꿔주기
    part_time_N = int(num_data['파트타임'])

    """## 지속성/일회성"""

    # @title 함수) 지속성 / 일회성 나누어서 scatter + box plot 그리는 함수

    def draw_box_plot(df, variable_of_interest,short='Yes', fig_size=(6,9),
                      rotation_angle=15, font_size_parameter=7,
                      custom_fig_title=None):

        if custom_fig_title is not None:
            fig_title = custom_fig_title
        else:
            fig_title = f'시급 분포 - {variable_of_interest} 별'

        # 단기 근무 여부
        df_short = df[df['일회성 근무 여부'] == short].copy()

        # x축 정렬
        if variable_of_interest == '지역 대분류':
            category_order = pd.CategoricalDtype(['서울', '인천', '경기 중부', '경기 외곽', '지방'], ordered=True)
            df_short[variable_of_interest] = df[variable_of_interest].astype(category_order)
        else:
            pass
        df_short.sort_values(variable_of_interest, inplace=True)

        if short == 'Yes':
            hourly_wage = '일회성 근무 시급'
            period = '근무형태 : 일회성'
        else:
            hourly_wage = '시급(엄밀히)'
            period = '근무형태 : 지속성'

        # 그래프 크기 및 초기 설정
        plt.figure(figsize=fig_size)

        # 카테고리별 평균 및 표준 편차, n수 계산
        grouped = df_short.groupby(variable_of_interest, observed=True)[hourly_wage]
        means = grouped.mean()
        stds = grouped.std()
        num_data = grouped.count()

        # Dot plot
        # plt.scatter(df_short[variable_of_interest], df_short[hourly_wage], alpha=0.5, color='black')
        sns.stripplot(x=variable_of_interest, y=hourly_wage, data=df_short, jitter=0.05, alpha=0.3, color='black')  # jitter 기능 쓰기 위해 seaborn 씀

        # Box plot
        positions = range(len(grouped))  # 각 그룹별 위치 설정

        # 각 그룹의 데이터를 리스트로 준비
        data = [group for name, group in grouped]

        plt.boxplot(data, positions=positions, patch_artist=True, showfliers=False, widths=0.2,
                    boxprops=dict(facecolor='yellow', color='black', alpha=0.2),
                    whiskerprops=dict(color='green', alpha=0),
                    capprops=dict(color='black', alpha=0),
                    flierprops=dict(marker='o', color='yellow', alpha=0, markersize=5),
                    medianprops=dict(color='gray', alpha=0)
        )

        # 카테고리 위치 조정
        plt.xticks(positions, grouped.groups.keys(), rotation=0)

        for region in means.index:
            # 평균값을 점으로 표시
            plt.plot(region, means[region], 'rs', markersize=7)  # 'ro'는 빨간색 원형 마커

            # 평균 시급 값 숫자로 표시, 텍스트 위치 오른쪽으로 조정
            plt.text(region, means[region], f'   {means[region]:.2f}', fontsize=15, ha = 'left', color='red')

            # 카테고리별 공고 개수 표시
            position = df_short[hourly_wage].min() - stds.max()*0.7
            plt.text(region, position, f'n = {num_data[region]}', fontsize=12, ha = 'center', color='black')

        # 그래프 제목 및 라벨
        plt.title(fig_title + '\n', fontsize=18, fontweight='bold')
        plt.xlabel(f'\n{variable_of_interest}', fontsize=15)
        plt.ylabel('시급 (단위 : 만 원)\n', fontsize=15)
        plt.grid(True)

        # legend 추가
        # 구인 공고와 IQR 범례에 사용할 맞춤 마커 생성
        job_marker = mlines.Line2D([], [], color='black', marker='o', linestyle='None', markersize=5, alpha=0.4, label='구인 공고')
        iqr_box = mlines.Line2D([], [], marker='s', color='black', markerfacecolor='yellow', markeredgewidth=1,
                            markeredgecolor='black', linestyle='None', markersize=15, alpha=0.3, label='IQR (interquartile range)')

        legend = plt.legend(handles=[job_marker, iqr_box], title=period, loc='upper right', fontsize=11)

        # 폰트 설정
        bold_font = font_manager.FontProperties(weight='bold')  # 'bold'로 글씨 굵게
        legend.get_title().set_fontproperties(bold_font)

        # y축 여백 설정
        plt.ylim(df_short[hourly_wage].min() - stds.max(), df_short[hourly_wage].max() + stds.max())

        # 레이아웃 조정
        plt.tight_layout()

        if custom_fig_title is not None:
            image_file_name = custom_fig_title
        else:
            image_file_name = '{} ({})'.format(fig_title, period)

        # 그래프 저장
        plt.savefig(os.path.join(output_dir, '{}.png'.format(image_file_name)), format='png', dpi=300) # 일반적으로 인쇄용으로는 최소 300 DPI가 권장됨. 화면 보기용으로는 150 DPI도 충분

        # 이미지에 워터마크 넣기
        add_watermark(image_file_name=image_file_name,
                      rotation_angle=rotation_angle, font_size_parameter=font_size_parameter)

        # ===================================== Statistics ===========================================
        if len(data) == 2:
            # 독립표본 t-검정 수행
            t_stat, p_value = stats.ttest_ind(data[0], data[1], equal_var=False)  # equal_var=False는 두 그룹의 분산이 같지 않을 때 사용
            print(f't-statistic: {t_stat:.3f}')
            print(f'p-value: {p_value:.15f}')
            alpha = 0.05  # 유의수준 설정
            if p_value < alpha:  # 결과 해석
                print("두 그룹 간의 평균 시급 차이는 통계적으로 유의미합니다.\n")
            else:
                print("두 그룹 간의 평균 시급 차이는 통계적으로 유의미하지 않습니다.\n")

            # 자유도 계산
            dfn = len(data[0]) + len(data[1]) - 2

            # 효과 크기 계산 (Cohen's d)
            mean_diff = data[0].mean() - data[1].mean()
            pooled_std = np.sqrt((data[0].var() + data[1].var()) / 2)
            cohen_d = mean_diff / pooled_std

            # 결과 출력
            print(f"독립표본 t-검정 결과: t({dfn}) = {t_stat:.3f}, p = {p_value:.3e}, Cohen's d = {cohen_d:.3f}")
            print(f"단기 근무 평균 시급: {data[0].mean():.3f} (SD = {data[0].std():.3f})")
            print(f"지속 근무 평균 시급: {data[1].mean():.3f} (SD = {data[1].std():.3f})")
            print('\n')

        else:
            # ANOVA
            print('그룹수 :', len(data))
            anova_result = f_oneway(*data) # *는 언패킹 연산자임. f_oneway(data[0], ... , data[N])과 같은 역할.

            # ANOVA 결과를 출력
            anova_text = f"ANOVA 결과: F-statistic = {anova_result.statistic:.2f}, p-value = {anova_result.pvalue:.10f}"
            print(anova_text, '\n')

            # 사후검정(post-hoc test) : Tukey's HSD
            tukey_result = pairwise_tukeyhsd(endog=df_comparison['시급(엄밀히)'], groups=df_comparison['지역 대분류'], alpha=0.05)
            print(tukey_result, '\n')
        # ===========================================================================================

        # 그래프 표시

        return means

    """### 지속성 근무"""

    draw_box_plot(df, variable_of_interest='플랫폼', short='No', fig_size=(6,10),
                  rotation_angle=15, font_size_parameter=7)

    draw_box_plot(df, variable_of_interest='내가 검토시 체크', short='No', fig_size=(6,10),
                  rotation_angle=15, font_size_parameter=7)

    continuous_work_means_by_big_category = draw_box_plot(
        df, variable_of_interest='지역 대분류', short='No', fig_size=(9,10),
        rotation_angle=15, font_size_parameter=10)

    # @title 지역별 풀타임 근무 시급 분포 그래프
    df_full_time = df[df['시간/week'] >= 36].copy()
    print(df_full_time.shape)

    full_time_work_means_by_big_category = draw_box_plot(
        df_full_time, variable_of_interest='지역 대분류', short='No', fig_size=(8,8),
        rotation_angle=15, font_size_parameter=10,
        custom_fig_title='지역별 풀타임 근무 시급 분포 그래프')

    # @title 지역별 풀타임 근무 시급 분포 그래프 - 퇴직금 고려

    # 1년 이상 근무시 1개월분의 급여가 퇴직금으로 지급되기 때문에 이를 고려해서 시급으로 환산하여 계산하여보자.
    # 그러면 12개월 일하면 13개월분의 급여가 나오는 셈이므로, 기존 급여에 13/12를 곱하면 된다.
    df_full_time_with_severance = df_full_time.copy()
    df_full_time_with_severance['시급(엄밀히)'] = df_full_time_with_severance['시급(엄밀히)'] * 13/12

    with_severance_full_time_work_means_by_big_category = draw_box_plot(
        df_full_time_with_severance, variable_of_interest='지역 대분류', short='No', fig_size=(8,8),
        rotation_angle=15, font_size_parameter=10,
        custom_fig_title='지역별 풀타임 근무 시급 분포 그래프 - 퇴직금 고려')

    # @title 지역별 주말(토,일) 근무 시급 분포 그래프
    df_weekend = df[(df['주말 근무 일수'] != 0) & (df['평일 근무 일수'] == 0)].copy()  # 주말만 근무

    weekend_means_by_big_category = draw_box_plot(
        df_weekend, variable_of_interest='지역 대분류', short='No', fig_size=(8,8),
        rotation_angle=15, font_size_parameter=10,
        custom_fig_title='지역별 주말(토,일) 근무 시급 분포 그래프')

    """### 일회성 근무"""

    draw_box_plot(df, variable_of_interest='플랫폼', short='Yes', fig_size=(6,10),
                  rotation_angle=15, font_size_parameter=5)

    draw_box_plot(df, variable_of_interest='내가 검토시 체크', short='Yes', fig_size=(6,10),
                  rotation_angle=15, font_size_parameter=5)

    one_time_work_means_by_big_category = draw_box_plot(
        df, variable_of_interest='지역 대분류', short='Yes', fig_size=(9,10),
        rotation_angle=15, font_size_parameter=10)

    """# 노션에 결과 업로드

    ## 함수들
    """

    # @title 주어진 블록의 모든 children을 삭제하는 함수 : clear_block_children
    def clear_block_children(notion, block_id):
        """
        주어진 블록의 모든 children을 삭제하는 함수.

        :param notion: Notion client 인스턴스
        :param block_id: 블록 ID
        """
        # block의 children을 불러옵니다.
        children = notion.blocks.children.list(block_id=block_id).get('results', [])

        # 각 child 블록을 삭제합니다.
        for child in children:
            child_id = child['id']
            notion.blocks.delete(block_id=child_id)

    # @title 노션에 이미지 업로드 하는 함수 : upload_image_to_notion
    def upload_image_to_notion_by_imgur(image_path, imgur_client_id, notion, page_ID):
        '''
        노션에 직접 이미지 업로드가 안돼서 imgur이라는 external hosting service를
        이용하여 업로드한 뒤, 그 url로 노션에 이미지를 추가하는 함수.
        참고) https://api.imgur.com/oauth2/addclient
        '''
        # Imgur에 이미지 업로드
        headers = {'Authorization': f'Client-ID {imgur_client_id}'}
        with open(image_path, 'rb') as f:
            image_data = f.read()
        response = requests.post(
            'https://api.imgur.com/3/upload',
            headers=headers,
            files={'image': image_data}
        )
        data = response.json()
        if data['success']:
            image_url = data['data']['link']
            print(f"이미지가 Imgur에 업로드 되었습니다 : {image_url}")
        else:
            raise Exception(f"❌ Failed to upload image: {data['data']['error']}")

        # 노션에 이미지 추가
        response = notion.blocks.children.append(
            block_id=page_ID,
            children=[
                {
                    "object": "block",
                    "type": "image",
                    "image": {
                        "type": "external",
                        "external": {
                            "url": image_url
                        }
                    }
                }
            ]
        )
        print("{} 이미지를 노션에 업로드 하였습니다.".format(image_path))

